wwv_flow_imp_page.create_report_region(
 p_id=>wwv_flow_imp.id(22510762550090596)
,p_name=>'Stock Allocations'
,p_static_id=>'stock-allocations'
,p_template=>4073835273271169698
,p_display_sequence=>30
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody:t-Region--noBorder'
,p_component_template_options=>'#DEFAULT#:t-Report--stretch:t-Report--staticRowColors:t-Report--rowHighlight:t-Report--horizontalBorders:t-Report--hideNoPagination'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select',
'    c.STOCK_ALLOCATION_ID as STOCK_ALLOCATION_ID',
'    , c.ALLOCATION_NUMBER as ALLOCATION_NUMBER',
'    , c.OUTBOUND_ORDER_LINE_ID as OUTBOUND_ORDER_LINE_ID',
'    , c.INVENTORY_BALANCE_ID as INVENTORY_BALANCE_ID',
'    , c.WAREHOUSE_ID as WAREHOUSE_ID',
'    , c.SOURCE_LOCATION_ID as SOURCE_LOCATION_ID',
'    , c.ITEM_ID as ITEM_ID',
'    , c.INVENTORY_LOT_ID as INVENTORY_LOT_ID',
'    , c.ITEM_SERIAL_ID as ITEM_SERIAL_ID',
'    , c.ALLOCATION_SEQUENCE as ALLOCATION_SEQUENCE',
'    , c.ALLOCATION_METHOD_CODE as ALLOCATION_METHOD_CODE',
'    , c.ALLOCATION_STATUS_CODE as ALLOCATION_STATUS_CODE',
'    , c.ALLOCATED_QUANTITY as ALLOCATED_QUANTITY',
'    , c.RESERVED_QUANTITY as RESERVED_QUANTITY',
'    , c.PICKED_QUANTITY as PICKED_QUANTITY',
'    , c.PACKED_QUANTITY as PACKED_QUANTITY',
'    , c.DISPATCHED_QUANTITY as DISPATCHED_QUANTITY',
'    , c.SHORT_QUANTITY as SHORT_QUANTITY',
'    , c.FIFO_BASIS_DATE as FIFO_BASIS_DATE',
'    , c.ALLOCATED_BY_USER_ID as ALLOCATED_BY_USER_ID',
'    , c.ALLOCATED_AT as ALLOCATED_AT',
'    , c.PICKED_BY_USER_ID as PICKED_BY_USER_ID',
'    , c.PICKED_AT as PICKED_AT',
'    , c.PACKED_BY_USER_ID as PACKED_BY_USER_ID',
'    , c.PACKED_AT as PACKED_AT',
'    , c.DISPATCHED_BY_USER_ID as DISPATCHED_BY_USER_ID',
'    , c.DISPATCHED_AT as DISPATCHED_AT',
'from SCM_STOCK_ALLOCATIONS c',
'join SCM_OUTBOUND_ORDER_LINES v',
'    on v.OUTBOUND_ORDER_LINE_ID = c.OUTBOUND_ORDER_LINE_ID',
'where',
'    v.OUTBOUND_ORDER_ID = to_number(:P56_OUTBOUND_ORDER_ID)',
'order by',
'    ALLOCATION_SEQUENCE asc'))
,p_ajax_enabled=>'Y'
,p_ajax_items_to_submit=>'P56_OUTBOUND_ORDER_ID'
,p_lazy_loading=>false
,p_query_row_template=>2540130677583398057
,p_query_num_rows=>15
,p_query_options=>'DERIVED_REPORT_COLUMNS'
,p_query_num_rows_type=>'NEXT_PREVIOUS_LINKS'
,p_pagination_display_position=>'BOTTOM_RIGHT'
,p_csv_output=>'N'
,p_prn_output=>'N'
,p_sort_null=>'L'
,p_plug_query_strip_html=>'N'
,p_comment=>'Lists stock allocations related to the selected outbound order.'
);
