,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select',
'    c.STOCK_COUNT_LINE_ID as STOCK_COUNT_LINE_ID',
'    , c.STOCK_COUNT_ID as STOCK_COUNT_ID',
'    , c.LINE_NUMBER as LINE_NUMBER',
'    , c.ITEM_ID as ITEM_ID',
'    , c.STORAGE_LOCATION_ID as STORAGE_LOCATION_ID',
'    , c.INVENTORY_LOT_ID as INVENTORY_LOT_ID',
'    , c.EXPECTED_QUANTITY as EXPECTED_QUANTITY',
'    , c.COUNTED_QUANTITY as COUNTED_QUANTITY',
'    , c.VARIANCE_QUANTITY as VARIANCE_QUANTITY',
'    , c.VARIANCE_REASON_CODE as VARIANCE_REASON_CODE',
'    , c.FIRST_COUNTED_BY_USER_ID as FIRST_COUNTED_BY_USER_ID',
'    , c.FIRST_COUNTED_AT as FIRST_COUNTED_AT',
'    , c.REVIEWED_BY_USER_ID as REVIEWED_BY_USER_ID',
'    , c.REVIEWED_AT as REVIEWED_AT',
'    , c.RESOLUTION_CODE as RESOLUTION_CODE',
'    , c.LINE_STATUS_CODE as LINE_STATUS_CODE',
'from SCM_STOCK_COUNT_LINES c',
'where',
'    c.STOCK_COUNT_ID = to_number(:P68_STOCK_COUNT_ID)',
'order by',
'    LINE_NUMBER asc'))
